import { getBankByShortName, getBankByBin } from '@/utils/bank-lookup';
import { calculateCRC16 } from '@/utils/crc16';
import { sanitizeContent, sanitizeAccountName } from '@/utils/string';

export interface VietQROptions {
  bankId: string; // Có thể truyền ShortName (VD: VCB) hoặc số BIN
  accountNo: string;
  accountName?: string; // Tên tài khoản (Bắt buộc phải có Tag 59 theo EMVCo)
  amount?: number; // Nếu không truyền sẽ sinh ra QR Tĩnh
  content?: string;
}

function formatTLV(tag: string, value: string): string {
  const length = value.length.toString().padStart(2, '0');
  return `${tag}${length}${value}`;
}

export function generateVietQR(options: VietQROptions): string {
  const { bankId, accountNo, accountName, amount, content } = options;
  
  if (!accountNo) {
    throw new Error('Account number is required');
  }

  // Chống tràn độ dài EMVCo và lỗi cú pháp
  if (accountNo.length > 50 || !/^[A-Za-z0-9]+$/.test(accountNo)) {
    throw new Error('Account number must be alphanumeric and <= 50 characters');
  }

  if (amount !== undefined) {
    if (amount <= 0 || !Number.isInteger(amount)) {
      throw new Error('Amount must be a positive integer');
    }
    if (amount.toString().length > 13) {
      throw new Error('Amount length exceeds EMVCo limit of 13 digits');
    }
  }

  const bank = getBankByBin(bankId) || getBankByShortName(bankId);
  if (!bank) {
    throw new Error(`Bank not found with ID: ${bankId}`);
  }

  // 00: Payload Format Indicator
  const tag00 = formatTLV('00', '01');
  
  // 01: Point of Initiation Method (11: Tĩnh, 12: Động)
  const isDynamic = amount !== undefined && amount > 0;
  const tag01 = formatTLV('01', isDynamic ? '12' : '11');

  // 38: Account Information (Chuẩn NAPAS 247)
  const guid = formatTLV('00', 'A000000727');
  const beneficiaryOrg = formatTLV('00', bank.bin) + formatTLV('01', accountNo);
  const beneficiaryInfo = formatTLV('01', beneficiaryOrg);
  const serviceCode = formatTLV('02', 'QRIBFTTA'); // QRIBFTTA = Chuyển khoản qua số tài khoản
  
  const tag38Value = guid + beneficiaryInfo + serviceCode;
  const tag38 = formatTLV('38', tag38Value);

  // 53: Currency Code (VNĐ = 704)
  const tag53 = formatTLV('53', '704');

  // 54: Transaction Amount
  let tag54 = '';
  if (isDynamic) {
    tag54 = formatTLV('54', amount!.toString());
  }

  // 58: Country Code
  const tag58 = formatTLV('58', 'VN');

  // 59: Merchant Name (Bắt buộc theo chuẩn EMVCo)
  const merchantName = accountName ? sanitizeAccountName(accountName) : 'NA';
  const tag59 = formatTLV('59', merchantName);

  // 60: Merchant City (Bắt buộc theo chuẩn EMVCo)
  const tag60 = formatTLV('60', 'VN');

  // 62: Additional Data Field (Nội dung chuyển khoản)
  let tag62 = '';
  if (content) {
    const safeContent = sanitizeContent(content);
    if (safeContent) {
      const purpose = formatTLV('08', safeContent);
      tag62 = formatTLV('62', purpose);
    }
  }

  // Ghép toàn bộ chuỗi trước khi tính mã kiểm tra CRC
  const payloadBeforeCRC = tag00 + tag01 + tag38 + tag53 + tag54 + tag58 + tag59 + tag60 + tag62;

  // 63: CRC (Cộng thêm ID 63 và Length 04 vào chuỗi để tính)
  const stringForCRC = payloadBeforeCRC + '6304';
  const crcValue = calculateCRC16(stringForCRC);
  
  return stringForCRC + crcValue;
}
